#include <stdio.h>
#include <limits.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long total = 0;
        int min1 = INT_MAX, min2 = INT_MAX;
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            total += x;
            if (x < min1) {
                min2 = min1;
                min1 = x;
            } else if (x < min2) {
                min2 = x;
            }
        }
        long long ans = 2 * total - (long long)(min1 + min2);
        printf("%lld\n", ans);
    }
    return 0;
}

